components.css:
.container {
  max-width: 1200px;
  margin-left: auto;
  margin-right: auto;
  padding-left: var(--a-space-lg);
  padding-right: var(--a-space-lg);
}

@media (max-width: 1024px) {
  .container {
    max-width: 960px;
  }
}

@media (max-width: 768px) {
  .container {
    max-width: 100%;
    padding-left: var(--a-space-md);
    padding-right: var(--a-space-md);
  }
}

.grid-2col {
  display: grid;
  gap: var(--a-space-lg);
  grid-template-columns: repeat(2, 1fr);
}

@media (max-width: 768px) {
  .grid-2col {
    grid-template-columns: 1fr;
  }
}

.grid-3col {
  display: grid;
  gap: var(--a-space-lg);
  grid-template-columns: repeat(auto-fit, minmax(250px, 1fr));
}

@media (max-width: 768px) {
  .grid-3col {
    grid-template-columns: 1fr;
  }
}

.sidebar-layout {
  display: grid;
  gap: var(--a-space-lg);
  grid-template-columns: 1fr 300px;
}

@media (max-width: 1024px) {
  .sidebar-layout {
    grid-template-columns: 1fr 250px;
  }
}

@media (max-width: 768px) {
  .sidebar-layout {
    grid-template-columns: 1fr;
  }
}

.flex-row {
  display: flex;
  gap: var(--a-space-md);
  flex-wrap: wrap;
}

.flex-row > * {
  flex: 1;
  min-width: 200px;
}

@media (max-width: 768px) {
  .flex-row > * {
    flex: 1 1 100%;
  }
}

.centered-layout {
  display: flex;
  align-items: center;
  justify-content: center;
  min-height: 100vh;
  text-align: center;
}

@media (max-width: 768px) {
  .centered-layout {
    min-height: auto;
    padding: var(--a-space-lg);
  }
}

header.hero {
  padding: var(--a-space-4xl) var(--a-space-lg);
  background: linear-gradient(
    135deg,
    var(--a-primary),
    color-mix(in oklch, var(--a-primary) 70%, transparent)
  );
  color: var(--a-surface-base);
  text-align: center;
}

header.hero h1 {
  margin: 0 0 var(--a-space-md) 0;
  font-size: var(--a-text-4xl);
}

header.hero p {
  margin: 0;
  font-size: var(--a-text-lg);
}

footer.footer {
  background: var(--a-surface-overlay);
  padding: var(--a-space-2xl) var(--a-space-lg);
  border-top: 1px solid var(--a-border);
}

footer.footer nav {
  display: inline-block;
  margin-right: var(--a-space-3xl);
}

@media (max-width: 768px) {
  footer.footer nav {
    display: block;
    margin-right: 0;
    margin-bottom: var(--a-space-lg);
  }
}
